  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-.2) * uAspect.xy;


vec2 uv6 = uv1;
float z = q29*2*length(uv1)+rand_frame * 32;
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-8,8);
vUv += .004*GetBlur1(vUv)*vec2 (0,1);//rs/20;


uv6 = .4*sin(uv1*18*rand_frame);
mus = .051/(length(uv6));
mus *= vec3 (1,.8,.5);

vec3 blur = GetBlur2(fract(vUv));

vec3 crisp= texture(sampler_main,vUv);

vec3 ret1 = crisp - blur*.03 + .15*mus;
vec2 uv2 = (vUvOriginal-.5)-vec2(.5,.5+0.1*q25);

q25 = 1;
ret = q25*(ret1*.99-.02) + (1-q25)* GetPixel(vUvOriginal);


